# rcpp distributions ----
## Setup ----

# Define a reference implementation of the inverse gamma log density in R
# for validation purposes.
dinvgamma_r <- function(x, shape, scale, logscale = TRUE) {
  ret <- shape * log(scale) - lgamma(shape) - (shape + 1) * log(x) - scale / x
  if (logscale) {
    return(ret)
  } else {
    return(exp(ret))
  }
}

## IO correctness ----
test_that("rcpp dinvgamma distribution works with correct inputs", {
  set.seed(123)

  # Derive shape and scale from mean (expected) and log_sd following the
  # formulas: shape = (expected / exp(log_sd))^2, scale = exp(2*log_sd)/expected
  expected_val <- 2.0
  log_sd_val <- log(0.5)
  shape <- (expected_val / exp(log_sd_val))^2
  scale <- exp(2 * log_sd_val) / expected_val
  y <- 1.0 / rgamma(1, shape = shape, rate = scale)

  # create a fims Rcpp object
  dinvgamma_ <- methods::new(DinvgammaDistribution)
  # populate class members
  dinvgamma_$observed_values[1]$value <- y
  dinvgamma_$expected_values[1]$value <- expected_val
  dinvgamma_$log_sd[1]$value <- log_sd_val
  # evaluate the density and compare with R reference
  #' @description Test that dinvgamma works with a single value input, e.g. a prior on a parameter.
  expect_equal(dinvgamma_$evaluate(), dinvgamma_r(y, shape, scale))
  clear()

  # simulate inverse gamma data for a vector
  n <- 10
  y <- 1.0 / rgamma(n, shape = shape, rate = scale)

  # create a fims Rcpp object
  dinvgamma_ <- methods::new(DinvgammaDistribution)
  # populate class members
  dinvgamma_$observed_values$resize(n)
  purrr::walk(
    seq_along(y),
    \(x) dinvgamma_$observed_values[x]$value <- y[x]
  )
  dinvgamma_$expected_values$resize(n)
  purrr::walk(
    seq_along(y),
    \(x) dinvgamma_$expected_values[x]$value <- expected_val
  )
  dinvgamma_$log_sd[1]$value <- log_sd_val
  # evaluate the density and compare with R reference
  #' @description Test that dinvgamma works with a vector of state variables, but scalar arguments, e.g., a random effect vector.
  expect_equal(dinvgamma_$evaluate(), sum(dinvgamma_r(y, shape, scale)))
  clear()

  # simulate inverse gamma data for a vector with vector log_sd
  y <- 1.0 / rgamma(n, shape = shape, rate = scale)

  # create a fims Rcpp object
  dinvgamma_ <- methods::new(DinvgammaDistribution)
  # populate class members
  dinvgamma_$observed_values$resize(n)
  purrr::walk(
    seq_along(y),
    \(x) dinvgamma_$observed_values[x]$value <- y[x]
  )
  dinvgamma_$expected_values$resize(n)
  purrr::walk(
    seq_along(y),
    \(x) dinvgamma_$expected_values[x]$value <- expected_val
  )
  dinvgamma_$log_sd$resize(n)
  purrr::walk(
    seq_along(y),
    \(x) dinvgamma_$log_sd[x]$value <- log_sd_val
  )
  # evaluate the density and compare with R reference
  #' @description Test that dinvgamma works with vectors of state variables (x) and arguments, e.g., an index likelihood vector.
  expect_equal(dinvgamma_$evaluate(), sum(dinvgamma_r(y, shape, scale)))
  clear()
})

## Edge handling ----
test_that("rcpp dinvgamma distribution returns correct outputs for edge cases", {
  expected_val <- 2.0
  log_sd_val <- log(0.5)
  shape <- (expected_val / exp(log_sd_val))^2
  scale <- exp(2 * log_sd_val) / expected_val

  # Test with a very small positive x
  y <- 0.001
  dinvgamma_ <- methods::new(DinvgammaDistribution)
  dinvgamma_$observed_values[1]$value <- y
  dinvgamma_$expected_values[1]$value <- expected_val
  dinvgamma_$log_sd[1]$value <- log_sd_val
  #' @description Test extreme observed values for dinvgamma (very small positive x) return expected output.
  expect_equal(dinvgamma_$evaluate(), dinvgamma_r(y, shape, scale))
  clear()

  # Test with a large positive x
  y <- 1000.0
  dinvgamma_ <- methods::new(DinvgammaDistribution)
  dinvgamma_$observed_values[1]$value <- y
  dinvgamma_$expected_values[1]$value <- expected_val
  dinvgamma_$log_sd[1]$value <- log_sd_val
  #' @description Test extreme observed values for dinvgamma (large positive x) return expected output.
  expect_equal(dinvgamma_$evaluate(), dinvgamma_r(y, shape, scale))
  clear()

  # Test with a large log_sd
  y <- 1.0
  log_sd_large <- 5.0
  shape_large <- (expected_val / exp(log_sd_large))^2
  scale_large <- exp(2 * log_sd_large) / expected_val
  dinvgamma_ <- methods::new(DinvgammaDistribution)
  dinvgamma_$observed_values[1]$value <- y
  dinvgamma_$expected_values[1]$value <- expected_val
  dinvgamma_$log_sd[1]$value <- log_sd_large
  #' @description Test extreme log_sd values for dinvgamma (large log_sd) return expected output.
  expect_equal(dinvgamma_$evaluate(), dinvgamma_r(y, shape_large, scale_large))
  clear()

  # Test with x = 0 (should return -Inf or NaN due to log(0))
  y <- 0.0
  dinvgamma_ <- methods::new(DinvgammaDistribution)
  dinvgamma_$observed_values[1]$value <- y
  dinvgamma_$expected_values[1]$value <- expected_val
  dinvgamma_$log_sd[1]$value <- log_sd_val
  #' @description Test that dinvgamma returns -Inf for x = 0.
  expect_true(is.nan(dinvgamma_$evaluate()) || is.infinite(dinvgamma_$evaluate()))
  clear()
})

## Error handling ----
test_that("rcpp dinvgamma distribution returns correct error messages", {
  expected_val <- 2.0
  log_sd_val <- log(0.5)
  shape <- (expected_val / exp(log_sd_val))^2
  scale <- exp(2 * log_sd_val) / expected_val
  n <- 10
  y <- 1.0 / rgamma(n, shape = shape, rate = scale)

  # create a fims Rcpp object
  dinvgamma_ <- methods::new(DinvgammaDistribution)
  # populate class members with mismatched sizes
  dinvgamma_$observed_values$resize(n)
  purrr::walk(
    seq_along(y),
    \(x) dinvgamma_$observed_values[x]$value <- y[x]
  )
  dinvgamma_$expected_values$resize(n)
  purrr::walk(
    seq_along(y),
    \(x) dinvgamma_$expected_values[x]$value <- expected_val
  )
  dinvgamma_$log_sd$resize(3)
  purrr::walk(
    1:3,
    \(x) dinvgamma_$log_sd[x]$value <- log_sd_val
  )
  #' @description dinvgamma should error out when there is a dimension mismatch where it is expecting log_sd to have a size 10 but is provided a size 3 vector.
  expect_error(
    object = dinvgamma_$evaluate(),
    regexp = "InvGammaLPDF::Vector .* out of bounds. .* 10 .* 3"
  )
  clear()
})
